-- CHECK Constraints
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'chk_users_email_format') THEN
    ALTER TABLE users ADD CONSTRAINT chk_users_email_format CHECK (email ~* '^[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Za-z]{2,}$');
  END IF;
END $$;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'chk_users_username_format') THEN
    ALTER TABLE users ADD CONSTRAINT chk_users_username_format CHECK (username ~* '^[a-zA-Z0-9_]{3,50}$');
  END IF;
END $$;
DO $$ BEGIN
  IF NOT EXISTS (SELECT 1 FROM pg_constraint WHERE conname = 'chk_users_display_name_length') THEN
    ALTER TABLE users ADD CONSTRAINT chk_users_display_name_length CHECK (char_length(display_name) >= 1 AND char_length(display_name) <= 255);
  END IF;
