-- Polymorphic Relationships
-- The following tables use polymorphic associations where a type column
-- discriminates which parent table the ID column references.
-- policies: resource_id + resource_type (prefix: resource)
-- policy_rules: subject_id + subject_type (prefix: subject)
-- events: resource_id + resource_type (prefix: resource)
-- audit_logs: resource_id + resource_type (prefix: resource)
-- outbox_events: aggregate_id + aggregate_type (prefix: aggregate)

CREATE INDEX idx_policies_resource_poly ON policies(resource_type, resource_id);
CREATE INDEX idx_policy_rules_subject_poly ON policy_rules(subject_type, subject_id);
CREATE INDEX idx_events_resource_poly ON events(resource_type, resource_id);
CREATE INDEX idx_audit_logs_resource_poly ON audit_logs(resource_type, resource_id);
CREATE INDEX idx_outbox_events_aggregate_poly ON outbox_events(aggregate_type, aggregate_id);

